package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Constructor;
import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class ReflectionHelperTest {

  // A sample class to simulate a record-like structure (since 'record' keyword is not recognized)
  static class SampleRecord {
    private final String name;
    private final int age;

    public SampleRecord(String name, int age) {
      this.name = name;
      this.age = age;
    }
  }

  // A sample non-record class for negative testing
  static class NonRecord {
    NonRecord() {}
  }

  @BeforeAll
  static void setup() {
    // No setup needed since RECORD_HELPER is static final and used internally
  }

  @Test
  void getCanonicalRecordConstructor_whenRecordClass_returnsConstructor() {
    Constructor<SampleRecord> constructor = ReflectionHelper.getCanonicalRecordConstructor(SampleRecord.class);
    assertNotNull(constructor);
    assertEquals(SampleRecord.class, constructor.getDeclaringClass());
    assertEquals(2, constructor.getParameterCount());
  }

  @Test
  void getCanonicalRecordConstructor_whenNonRecordClass_throwsException() {
    RuntimeException exception = assertThrows(RuntimeException.class,
        () -> ReflectionHelper.getCanonicalRecordConstructor(NonRecord.class));
    assertNotNull(exception.getMessage());
  }

  @Test
  void getCanonicalRecordConstructor_nullClass_throwsNullPointerException() {
    assertThrows(NullPointerException.class, () -> ReflectionHelper.getCanonicalRecordConstructor(null));
  }

  @Test
  void getCanonicalRecordConstructor_internalRecordHelperThrowsReflectiveOperationException() throws Exception {
    Field recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);
    Object originalRecordHelper = recordHelperField.get(null);

    Object mockRecordHelper = mock(originalRecordHelper.getClass());
    when(mockRecordHelper.getClass().getMethod("getCanonicalRecordConstructor", Class.class)
        .invoke(mockRecordHelper, SampleRecord.class))
        .thenThrow(new ReflectiveOperationException("mocked exception"));

    // Since we cannot mock the method via reflection easily, we use a proxy mock with Mockito's doThrow:
    // So instead, mock the method directly on the mockRecordHelper object:
    // But because getCanonicalRecordConstructor is called on RECORD_HELPER, which is of type RecordHelper,
    // and we only have Object, we can use Mockito's doThrow on the mockRecordHelper:

    // To do this, cast mockRecordHelper to the proper interface using reflection proxy:
    // But simpler is to use Mockito's when().thenThrow() on the mockRecordHelper's method call:
    // So we do:
    // when(mockRecordHelper.getCanonicalRecordConstructor(SampleRecord.class)).thenThrow(...);
    // But mockRecordHelper is Object, so cast:
    // The below works if we cast to the class of originalRecordHelper:

    Object recordHelperClass = originalRecordHelper.getClass();
    // Create a spy of originalRecordHelper to override the method behavior:
    Object spyRecordHelper = spy(originalRecordHelper);
    when(spyRecordHelper.getClass().getMethod("getCanonicalRecordConstructor", Class.class)
        .invoke(spyRecordHelper, SampleRecord.class))
        .thenThrow(new ReflectiveOperationException("mocked exception"));

    // But above is complicated, simpler approach is:
    // Use Mockito's doThrow on spyRecordHelper:
    // But doThrow requires method call, so we do reflection invoke inside lambda:

    // So we do:
    doAnswer(invocation -> {
      throw new ReflectiveOperationException("mocked exception");
    }).when(spyRecordHelper).getClass().getMethod("getCanonicalRecordConstructor", Class.class)
        .invoke(spyRecordHelper, SampleRecord.class);

    // This is complicated due to reflection and Mockito limitations.
    // Instead, use a dynamic proxy or simply create a subclass that throws exception.
    // But since RecordHelper is private/internal, we do the following:

    // Directly set the RECORD_HELPER field to a mock of the same type that throws exception when getCanonicalRecordConstructor is called:
    Object proxyRecordHelper = java.lang.reflect.Proxy.newProxyInstance(
        recordHelperField.getType().getClassLoader(),
        new Class[]{recordHelperField.getType()},
        (proxy, method, args) -> {
          if (method.getName().equals("getCanonicalRecordConstructor")) {
            throw new ReflectiveOperationException("mocked exception");
          }
          return method.invoke(originalRecordHelper, args);
        });

    recordHelperField.set(null, proxyRecordHelper);

    RuntimeException ex = assertThrows(RuntimeException.class,
        () -> ReflectionHelper.getCanonicalRecordConstructor(SampleRecord.class));
    assertTrue(ex.getMessage().contains("mocked exception"));

    // Restore original RECORD_HELPER
    recordHelperField.set(null, originalRecordHelper);
  }
}
